import { pgTable, serial, text, integer, real, boolean, timestamp } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod/v4";

export const extractionJobsTable = pgTable("extraction_jobs", {
  id: serial("id").primaryKey(),
  emailText: text("email_text").notNull(),
  subject: text("subject"),
  emailType: text("email_type").notNull().default("Unknown"),
  pipeline: text("pipeline").notNull().default("rule-based"),
  confidence: real("confidence").notNull().default(0),
  extractedEntriesJson: text("extracted_entries_json").notNull().default("[]"),
  processingMs: integer("processing_ms").notNull().default(0),
  llmUsed: boolean("llm_used").notNull().default(false),
  estimatedCostUsd: real("estimated_cost_usd").notNull().default(0),
  createdAt: timestamp("created_at").notNull().defaultNow(),
});

export const insertExtractionJobSchema = createInsertSchema(extractionJobsTable).omit({ id: true, createdAt: true });
export type InsertExtractionJob = z.infer<typeof insertExtractionJobSchema>;
export type ExtractionJob = typeof extractionJobsTable.$inferSelect;

// Maritime Email Extraction Engine — Rule-Based + Template Parser

export type EmailType = "VC" | "TC" | "Tonnage" | "Mixed" | "Unknown";
export type Pipeline = "rule-based" | "template" | "llm-fallback";
export type EntryType = "VC" | "TC" | "Tonnage";

export interface ExtractedFields {
  email_type?: string | null;
  cargo_name?: string | null;
  account_name?: string | null;
  cargo_type?: string | null;
  tonnage_name?: string | null;
  tonnage_type?: string | null;
  min_size?: number | null;
  max_size?: number | null;
  region?: string | null;
  matching_region?: string | null;
  load_port?: string | null;
  discharge_port?: string | null;
  del_port?: string | null;
  redel_port?: string | null;
  port?: string | null;
  open_date?: string | null;
  close_date?: string | null;
  laycan_start_date?: string | null;
  laycan_end_date?: string | null;
  duration?: string | null;
  dwt?: string | null;
  pic?: string | null;
  email_id?: string | null;
  phone_number?: string | null;
  restriction?: string | null;
  reason?: string | null;
  latitude?: number | null;
  longitude?: number | null;
}

export interface ExtractedEntry {
  entryType: EntryType;
  confidence: number;
  extractionMethod: Pipeline;
  fields: ExtractedFields;
}

export interface ExtractionResult {
  emailType: EmailType;
  pipeline: Pipeline;
  confidence: number;
  extractedEntries: ExtractedEntry[];
  processingMs: number;
  llmUsed: boolean;
  estimatedCostUsd: number;
}

// ─── Maritime Knowledge Base ──────────────────────────────────────────────────

const REGION_MAP: Record<string, string> = {
