const PORT_ABBREVS: Record<string, string> = {
  BIK: "Bandar Imam Khomeini, Iran",
  KANDLA: "Kandla, India",
  KAKINADA: "Kakinada, India",
  VIZAG: "Visakhapatnam, India",
