import { Link, useLocation } from "wouter";
import { LayoutDashboard, Upload, History, BookOpen, Anchor, Menu, X } from "lucide-react";
import { useState } from "react";
import { cn } from "@/lib/utils";

const NAV_ITEMS = [
  { href: "/", label: "Dashboard", icon: LayoutDashboard },
  { href: "/extract", label: "Extract Email", icon: Upload },
  { href: "/history", label: "History", icon: History },
  { href: "/knowledge", label: "Knowledge Base", icon: BookOpen },
];

function NavLink({ href, label, icon: Icon, onClick }: { href: string; label: string; icon: React.ComponentType<{ className?: string }>; onClick?: () => void }) {
  const [location] = useLocation();
  const isActive = href === "/" ? location === "/" : location.startsWith(href);
  return (
    <Link
      href={href}
      onClick={onClick}
      className={cn(
        "flex items-center gap-3 px-3 py-2.5 rounded text-sm font-medium transition-all duration-150",
        isActive
          ? "bg-primary/15 text-primary border border-primary/20"
          : "text-muted-foreground hover:text-foreground hover:bg-white/5"
      )}
      data-testid={`nav-${label.toLowerCase().replace(/\s+/g, "-")}`}
    >
      <Icon className="h-4 w-4 flex-shrink-0" />
      {label}
    </Link>
  );
}

export function Layout({ children }: { children: React.ReactNode }) {
  const [mobileOpen, setMobileOpen] = useState(false);

  return (
    <div className="flex min-h-screen bg-background">
      {/* Sidebar — desktop */}
      <aside className="hidden md:flex flex-col w-56 border-r border-border bg-sidebar shrink-0">
        <div className="flex items-center gap-2.5 px-4 py-4 border-b border-border">
          <div className="flex items-center justify-center w-7 h-7 rounded bg-primary/15 border border-primary/20">
            <Anchor className="h-3.5 w-3.5 text-primary" />
          </div>
          <div>
            <p className="text-xs font-bold text-foreground tracking-wide">MARITIME</p>
            <p className="text-[10px] text-muted-foreground tracking-widest uppercase">Extractor</p>
          </div>
        </div>
        <nav className="flex flex-col gap-1 p-3 flex-1">
          {NAV_ITEMS.map(item => (
            <NavLink key={item.href} {...item} />
          ))}
        </nav>
        <div className="px-4 py-3 border-t border-border">
          <p className="text-[10px] text-muted-foreground font-mono">Rule-Based Engine v1.0</p>
          <p className="text-[10px] text-muted-foreground/60">Hybrid extraction pipeline</p>
        </div>
      </aside>

      {/* Mobile sidebar */}
      {mobileOpen && (
        <div className="fixed inset-0 z-50 md:hidden">
          <div className="absolute inset-0 bg-black/60" onClick={() => setMobileOpen(false)} />
          <aside className="absolute left-0 top-0 bottom-0 w-56 flex flex-col bg-sidebar border-r border-border">
            <div className="flex items-center justify-between px-4 py-4 border-b border-border">
              <div className="flex items-center gap-2.5">
                <div className="flex items-center justify-center w-7 h-7 rounded bg-primary/15 border border-primary/20">
                  <Anchor className="h-3.5 w-3.5 text-primary" />
                </div>
                <div>
                  <p className="text-xs font-bold text-foreground tracking-wide">MARITIME</p>
                  <p className="text-[10px] text-muted-foreground tracking-widest uppercase">Extractor</p>
                </div>
              </div>
              <button onClick={() => setMobileOpen(false)} className="text-muted-foreground hover:text-foreground">
                <X className="h-4 w-4" />
              </button>
            </div>
            <nav className="flex flex-col gap-1 p-3 flex-1">
              {NAV_ITEMS.map(item => (
                <NavLink key={item.href} {...item} onClick={() => setMobileOpen(false)} />
              ))}
            </nav>
          </aside>
        </div>
      )}

      {/* Main content */}
      <div className="flex flex-col flex-1 min-w-0">
        {/* Mobile topbar */}
        <header className="md:hidden flex items-center gap-3 px-4 py-3 border-b border-border bg-sidebar">
          <button onClick={() => setMobileOpen(true)} className="text-muted-foreground hover:text-foreground" data-testid="button-mobile-menu">
            <Menu className="h-5 w-5" />
          </button>
          <div className="flex items-center gap-2">
            <Anchor className="h-4 w-4 text-primary" />
            <span className="text-sm font-bold tracking-wide">MARITIME EXTRACTOR</span>
          </div>
        </header>
        <main className="flex-1 overflow-auto">
          {children}
        </main>
      </div>
    </div>
  );
}

import { useState } from "react";
import { useExtractEmail, getListExtractionsQueryKey, getGetStatsQueryKey } from "@workspace/api-client-react";
import { useQueryClient } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Upload, ChevronDown, ChevronUp, Zap, AlertTriangle, CheckCircle, Anchor } from "lucide-react";
import { cn } from "@/lib/utils";

const SAMPLE_EMAIL = `Dear All,

Good day. 

Kindly propose suitable tonnage for the below fully firm requirement:

Account: YB Global Shipping LLC FZ
Vessel Type: SUPRA/ULTRAMAX
Cargo: Bulk Harmless Cargo
Tonnage: 58K - 60K  DWT VESSEL (Grabber Fitted)
Laycan: END JULY, 2025
Delivery: 1SP WAFR
Redelivery: 1SP South China
Duration: ABOUT 45 TO 55 DAYS

Adcom: 3.75%

Ayush Sharma
Chartering,
Mobile/WhatsApp: +91 9523757703
Teams: ayushsharma9491@outlook.com

YB Global Shipping LLC-FZ
chartering@ybglobalshipping.com`;

type ExtractionJob = {
  id: number;
  emailType: string;
  pipeline: string;
  confidence: number;
  extractedEntries: Array<{
    entryType: string;
    confidence: number;
    extractionMethod: string;
    fields: Record<string, string | number | null | undefined>;
  }>;
  processingMs: number;
  llmUsed: boolean;
  estimatedCostUsd: number;
};

function PipelineBadge({ method }: { method: string }) {
  const map: Record<string, { label: string; cls: string }> = {
    "rule-based": { label: "Rule-Based", cls: "bg-green-500/10 text-green-400 border-green-500/20" },
    "template": { label: "Template", cls: "bg-primary/10 text-primary border-primary/20" },
    "llm-fallback": { label: "LLM Fallback", cls: "bg-accent/10 text-accent border-accent/20" },
  };
  const cfg = map[method] ?? { label: method, cls: "bg-muted text-muted-foreground border-border" };
  return <span className={`inline-flex items-center gap-1 px-2 py-0.5 text-xs font-medium rounded border ${cfg.cls}`}>{cfg.label}</span>;
}

function TypeBadge({ type }: { type: string }) {
  const map: Record<string, string> = {
    VC: "bg-blue-500/10 text-blue-400 border-blue-500/20",
    TC: "bg-purple-500/10 text-purple-400 border-purple-500/20",
    Tonnage: "bg-cyan-500/10 text-cyan-400 border-cyan-500/20",
    Mixed: "bg-orange-500/10 text-orange-400 border-orange-500/20",
    Unknown: "bg-muted text-muted-foreground border-border",
  };
  return <span className={`inline-flex items-center px-2 py-0.5 text-xs font-medium rounded border ${map[type] ?? map.Unknown}`}>{type}</span>;
}

function FieldRow({ label, value }: { label: string; value: string | number | null | undefined }) {
  if (value === null || value === undefined || value === "") return null;
  return (
    <div className="flex gap-2 py-1.5 border-b border-border/40 last:border-0 text-xs">
      <span className="text-muted-foreground font-mono w-40 shrink-0">{label}</span>
      <span className="text-foreground font-medium break-words">{String(value)}</span>
    </div>
  );
}

const FIELD_LABELS: Record<string, string> = {
  email_type: "Email Type", cargo_name: "Cargo Name", account_name: "Account",
  cargo_type: "Cargo Type", tonnage_name: "Vessel Name", tonnage_type: "Vessel Type",
  min_size: "Min Size (MT)", max_size: "Max Size (MT)", region: "Region",
  load_port: "Load Port", discharge_port: "Discharge Port",
  del_port: "Delivery Port", redel_port: "Redelivery Port",
  port: "Port", open_date: "Open Date", close_date: "Close Date",
  laycan_start_date: "Laycan Start", laycan_end_date: "Laycan End",
  duration: "Duration", dwt: "DWT", pic: "Person in Charge",
  email_id: "Email", phone_number: "Phone", restriction: "Restrictions",
};

function EntryCard({ entry, index }: { entry: ExtractionJob["extractedEntries"][0]; index: number }) {
  const [open, setOpen] = useState(true);
  const filledCount = Object.values(entry.fields).filter(v => v !== null && v !== undefined).length;

  return (
    <div className="border border-border rounded overflow-hidden" data-testid={`entry-card-${index}`}>
      <button
        className="w-full flex items-center justify-between px-4 py-3 bg-card/60 hover:bg-card/80 transition-colors text-left"
        onClick={() => setOpen(!open)}
        data-testid={`button-toggle-entry-${index}`}
      >
        <div className="flex items-center gap-3">
          <TypeBadge type={entry.entryType} />
          <PipelineBadge method={entry.extractionMethod} />
          <span className="text-xs text-muted-foreground">{filledCount} fields extracted</span>
        </div>
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-1.5">
            <div className="w-16 h-1.5 bg-muted rounded-full overflow-hidden">
              <div className="h-full bg-primary rounded-full" style={{ width: `${entry.confidence * 100}%` }} />
            </div>
            <span className="text-xs font-mono text-muted-foreground">{(entry.confidence * 100).toFixed(0)}%</span>
          </div>
          {open ? <ChevronUp className="h-3.5 w-3.5 text-muted-foreground" /> : <ChevronDown className="h-3.5 w-3.5 text-muted-foreground" />}
        </div>
      </button>
      {open && (
        <div className="px-4 py-3 bg-card/30">
          {Object.entries(entry.fields).map(([key, val]) => (
            <FieldRow key={key} label={FIELD_LABELS[key] ?? key} value={val as string | number | null} />
          ))}
        </div>
      )}
    </div>
  );
}

export default function Extract() {
  const [emailText, setEmailText] = useState("");
  const [result, setResult] = useState<ExtractionJob | null>(null);
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const extractMutation = useExtractEmail();

  const handleExtract = () => {
    if (!emailText.trim()) {
      toast({ title: "Email text required", description: "Paste a maritime email to extract.", variant: "destructive" });
      return;
    }
    extractMutation.mutate(
      { data: { emailText } },
      {
        onSuccess: (data) => {
          setResult(data as unknown as ExtractionJob);
          queryClient.invalidateQueries({ queryKey: getListExtractionsQueryKey() });
          queryClient.invalidateQueries({ queryKey: getGetStatsQueryKey() });
          toast({ title: "Extraction complete", description: `${(data as unknown as ExtractionJob).extractedEntries.length} entries extracted` });
        },
        onError: () => {
          toast({ title: "Extraction failed", description: "Check your email text and try again.", variant: "destructive" });
        },
      }
    );
  };

  return (
    <div className="p-6 max-w-5xl" data-testid="page-extract">
      <div className="mb-6">
        <h1 className="text-xl font-bold text-foreground tracking-tight">Extract Email</h1>
        <p className="text-sm text-muted-foreground mt-0.5">Paste a maritime email to extract structured data</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Input Panel */}
        <div className="space-y-3">
          <div className="flex items-center justify-between">
            <p className="text-xs font-medium text-muted-foreground uppercase tracking-widest">Email Input</p>
            <button
              className="text-xs text-primary hover:text-primary/80 transition-colors"
              onClick={() => setEmailText(SAMPLE_EMAIL)}
              data-testid="button-load-sample"
            >
              Load sample email
            </button>
          </div>
          <Textarea
            value={emailText}
            onChange={e => setEmailText(e.target.value)}
            placeholder="Paste maritime email here..."
            className="font-mono text-xs min-h-[380px] bg-card border-border resize-none"
            data-testid="input-email-text"
          />
          <div className="flex items-center gap-3">
            <Button
              onClick={handleExtract}
              disabled={extractMutation.isPending}
              className="flex items-center gap-2"
              data-testid="button-extract"
            >
              {extractMutation.isPending ? (
                <><span className="animate-pulse">Processing...</span></>
              ) : (
                <><Zap className="h-4 w-4" />Extract Data</>
              )}
            </Button>
            {emailText && (
              <button
                className="text-xs text-muted-foreground hover:text-foreground transition-colors"
                onClick={() => { setEmailText(""); setResult(null); }}
                data-testid="button-clear"
              >
                Clear
              </button>
            )}
          </div>

          {/* Pipeline info */}
          <div className="p-3 bg-card border border-border rounded">
            <p className="text-xs font-semibold text-foreground mb-2 flex items-center gap-1.5">
              <Anchor className="h-3 w-3 text-primary" />
              Extraction Pipeline
            </p>
            <div className="space-y-1.5">
              {[
                { step: "1", label: "Rule Engine", desc: "Regex + maritime patterns", color: "text-green-400" },
                { step: "2", label: "Template Parser", desc: "Known broker formats", color: "text-primary" },
                { step: "3", label: "LLM Fallback", desc: "Only for complex emails", color: "text-accent" },
              ].map(item => (
                <div key={item.step} className="flex items-start gap-2 text-xs">
                  <span className={`font-mono font-bold ${item.color}`}>[{item.step}]</span>
                  <span className="text-foreground font-medium">{item.label}</span>
                  <span className="text-muted-foreground">— {item.desc}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Results Panel */}
        <div className="space-y-3">
          <p className="text-xs font-medium text-muted-foreground uppercase tracking-widest">Extraction Results</p>

          {extractMutation.isPending && (
            <div className="space-y-3">
              <Skeleton className="h-24" />
              <Skeleton className="h-48" />
            </div>
          )}

          {!extractMutation.isPending && !result && (
            <div className="flex flex-col items-center justify-center h-80 bg-card border border-dashed border-border rounded text-center px-6">
              <Upload className="h-8 w-8 text-muted-foreground/40 mb-3" />
              <p className="text-sm text-muted-foreground">Results will appear here</p>
              <p className="text-xs text-muted-foreground/60 mt-1">Paste an email and click Extract</p>
            </div>
          )}

          {result && !extractMutation.isPending && (
            <div className="space-y-3" data-testid="extraction-results">
              {/* Meta */}
              <div className="p-3 bg-card border border-border rounded">
                <div className="grid grid-cols-2 gap-x-4 gap-y-2 text-xs">
                  <div>
                    <span className="text-muted-foreground">Type</span>
                    <div className="mt-1"><TypeBadge type={result.emailType} /></div>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Pipeline</span>
                    <div className="mt-1"><PipelineBadge method={result.pipeline} /></div>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Entries</span>
                    <p className="font-mono font-bold text-foreground mt-0.5">{result.extractedEntries.length}</p>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Confidence</span>
                    <p className="font-mono font-bold text-foreground mt-0.5">{(result.confidence * 100).toFixed(1)}%</p>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Speed</span>
                    <p className="font-mono text-foreground mt-0.5">{result.processingMs}ms</p>
                  </div>
                  <div>
                    <span className="text-muted-foreground">Cost</span>
                    <p className="font-mono text-accent mt-0.5">${result.estimatedCostUsd.toFixed(4)}</p>
                  </div>
                </div>

                <div className={cn(
                  "mt-3 flex items-center gap-1.5 text-xs py-1.5 px-2 rounded",
                  result.llmUsed ? "bg-accent/10 text-accent" : "bg-green-500/10 text-green-400"
                )}>
                  {result.llmUsed
                    ? <><AlertTriangle className="h-3 w-3" />LLM was used for this extraction</>
                    : <><CheckCircle className="h-3 w-3" />Extracted without LLM — $0.0001 cost</>
                  }
                </div>
              </div>

              {/* Entry cards */}
              <div className="space-y-2 max-h-[480px] overflow-y-auto pr-1">
                {result.extractedEntries.length === 0 ? (
                  <div className="p-4 bg-card border border-border rounded text-center text-sm text-muted-foreground">
                    No entries could be extracted from this email
                  </div>
                ) : (
                  result.extractedEntries.map((entry, i) => (
                    <EntryCard key={i} entry={entry} index={i} />
                  ))
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { useState } from "react";
import { useListExtractions, useDeleteExtraction, getListExtractionsQueryKey } from "@workspace/api-client-react";
import { useQueryClient } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { Link } from "wouter";
import { Skeleton } from "@/components/ui/skeleton";
import { Trash2, ExternalLink, ChevronLeft, ChevronRight, Filter } from "lucide-react";
import { useToast as useToast2 } from "@/hooks/use-toast";

type EmailTypeFilter = "VC" | "TC" | "Tonnage" | "Mixed" | "Unknown" | "";

const PAGE_SIZE = 10;

function PipelineBadge({ method }: { method: string }) {
  const map: Record<string, string> = {
    "rule-based": "bg-green-500/10 text-green-400 border-green-500/20",
    "template": "bg-primary/10 text-primary border-primary/20",
    "llm-fallback": "bg-accent/10 text-accent border-accent/20",
  };
  const labels: Record<string, string> = {
    "rule-based": "Rule-Based", "template": "Template", "llm-fallback": "LLM",
  };
  return (
    <span className={`inline-flex items-center px-1.5 py-0.5 text-xs rounded border ${map[method] ?? "bg-muted text-muted-foreground border-border"}`}>
      {labels[method] ?? method}
    </span>
  );
}

function TypeBadge({ type }: { type: string }) {
  const map: Record<string, string> = {
    VC: "bg-blue-500/10 text-blue-400 border-blue-500/20",
    TC: "bg-purple-500/10 text-purple-400 border-purple-500/20",
    Tonnage: "bg-cyan-500/10 text-cyan-400 border-cyan-500/20",
    Mixed: "bg-orange-500/10 text-orange-400 border-orange-500/20",
    Unknown: "bg-muted text-muted-foreground border-border",
  };
  return <span className={`inline-flex items-center px-1.5 py-0.5 text-xs rounded border ${map[type] ?? map.Unknown}`}>{type}</span>;
}

export default function History() {
  const [page, setPage] = useState(0);
  const [typeFilter, setTypeFilter] = useState<EmailTypeFilter>("");
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const params = {
    limit: PAGE_SIZE,
    offset: page * PAGE_SIZE,
    ...(typeFilter ? { emailType: typeFilter } : {}),
  };

  const { data, isLoading } = useListExtractions(params, {
    query: { queryKey: getListExtractionsQueryKey(params) },
  });
  const deleteMutation = useDeleteExtraction();

  const handleDelete = (id: number) => {
    deleteMutation.mutate({ id }, {
      onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: getListExtractionsQueryKey() });
        toast({ title: "Deleted", description: "Extraction removed from history" });
      },
    });
  };

  const totalPages = data ? Math.ceil(data.total / PAGE_SIZE) : 1;

  return (
    <div className="p-6 space-y-5" data-testid="page-history">
      <div className="flex items-start justify-between">
        <div>
          <h1 className="text-xl font-bold text-foreground tracking-tight">Extraction History</h1>
          <p className="text-sm text-muted-foreground mt-0.5">
            {data ? `${data.total.toLocaleString()} total extractions` : "Loading..."}
          </p>
        </div>

        {/* Filter */}
        <div className="flex items-center gap-2">
          <Filter className="h-3.5 w-3.5 text-muted-foreground" />
          <select
            value={typeFilter}
            onChange={e => { setTypeFilter(e.target.value as EmailTypeFilter); setPage(0); }}
            className="text-xs bg-card border border-border rounded px-2 py-1.5 text-foreground focus:outline-none focus:ring-1 focus:ring-primary"
            data-testid="select-type-filter"
          >
            <option value="">All Types</option>
            <option value="VC">VC (Voyage Charter)</option>
            <option value="TC">TC (Time Charter)</option>
            <option value="Tonnage">Tonnage</option>
            <option value="Mixed">Mixed</option>
          </select>
        </div>
      </div>

      {/* Table */}
      <div className="bg-card border border-border rounded overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-xs">
            <thead>
              <tr className="border-b border-border bg-muted/20">
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest">Date</th>
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest">Type</th>
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest">Pipeline</th>
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest">Entries</th>
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest">Confidence</th>
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest">Speed</th>
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest">Cost</th>
                <th className="px-4 py-2.5" />
              </tr>
            </thead>
            <tbody>
              {isLoading && (
                [...Array(5)].map((_, i) => (
                  <tr key={i} className="border-b border-border/40">
                    {[...Array(8)].map((_, j) => (
                      <td key={j} className="px-4 py-3"><Skeleton className="h-3 w-full" /></td>
                    ))}
                  </tr>
                ))
              )}
              {!isLoading && data?.items.length === 0 && (
                <tr>
                  <td colSpan={8} className="px-4 py-12 text-center text-muted-foreground">
                    No extractions found. Try the Extract tab to process an email.
                  </td>
                </tr>
              )}
              {!isLoading && data?.items.map(job => (
                <tr
                  key={job.id}
                  className="border-b border-border/40 hover:bg-white/2 transition-colors"
                  data-testid={`row-extraction-${job.id}`}
                >
                  <td className="px-4 py-3 font-mono text-muted-foreground whitespace-nowrap">
                    {new Date(job.createdAt).toLocaleDateString("en-GB", { day: "2-digit", month: "short", hour: "2-digit", minute: "2-digit" })}
                  </td>
                  <td className="px-4 py-3"><TypeBadge type={job.emailType} /></td>
                  <td className="px-4 py-3"><PipelineBadge method={job.pipeline} /></td>
                  <td className="px-4 py-3 font-mono text-foreground">{(job.extractedEntries as unknown[]).length}</td>
                  <td className="px-4 py-3">
                    <div className="flex items-center gap-1.5">
                      <div className="w-12 h-1 bg-muted rounded-full overflow-hidden">
                        <div className="h-full bg-primary rounded-full" style={{ width: `${job.confidence * 100}%` }} />
                      </div>
                      <span className="font-mono text-muted-foreground">{(job.confidence * 100).toFixed(0)}%</span>
                    </div>
                  </td>
                  <td className="px-4 py-3 font-mono text-muted-foreground">{job.processingMs}ms</td>
                  <td className="px-4 py-3 font-mono text-accent">${job.estimatedCostUsd.toFixed(4)}</td>
                  <td className="px-4 py-3">
                    <div className="flex items-center gap-2">
                      <Link href={`/history/${job.id}`} data-testid={`link-detail-${job.id}`}>
                        <ExternalLink className="h-3.5 w-3.5 text-muted-foreground hover:text-primary transition-colors cursor-pointer" />
                      </Link>
                      <button
                        onClick={() => handleDelete(job.id)}
                        disabled={deleteMutation.isPending}
                        data-testid={`button-delete-${job.id}`}
                      >
                        <Trash2 className="h-3.5 w-3.5 text-muted-foreground hover:text-destructive transition-colors" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* Pagination */}
        {data && totalPages > 1 && (
          <div className="flex items-center justify-between px-4 py-3 border-t border-border">
            <p className="text-xs text-muted-foreground">
              {page * PAGE_SIZE + 1}–{Math.min((page + 1) * PAGE_SIZE, data.total)} of {data.total}
            </p>
            <div className="flex items-center gap-1">
              <button
                onClick={() => setPage(p => Math.max(0, p - 1))}
                disabled={page === 0}
                className="p-1.5 rounded hover:bg-muted disabled:opacity-40 transition-colors"
                data-testid="button-page-prev"
              >
                <ChevronLeft className="h-3.5 w-3.5" />
              </button>
              <span className="text-xs text-muted-foreground px-2">{page + 1} / {totalPages}</span>
              <button
                onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))}
                disabled={page >= totalPages - 1}
                className="p-1.5 rounded hover:bg-muted disabled:opacity-40 transition-colors"
                data-testid="button-page-next"
              >
                <ChevronRight className="h-3.5 w-3.5" />
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

import { useGetExtraction, getGetExtractionQueryKey } from "@workspace/api-client-react";
import { Link } from "wouter";
import { Skeleton } from "@/components/ui/skeleton";
import { ArrowLeft, Clock, DollarSign, CheckCircle, AlertTriangle } from "lucide-react";

type ExtractedEntry = {
  entryType: string;
  confidence: number;
  extractionMethod: string;
  fields: Record<string, string | number | null | undefined>;
};

const FIELD_LABELS: Record<string, string> = {
  email_type: "Email Type", cargo_name: "Cargo Name", account_name: "Account",
  cargo_type: "Cargo Type", tonnage_name: "Vessel Name", tonnage_type: "Vessel Type",
  min_size: "Min Size (MT)", max_size: "Max Size (MT)", region: "Region",
  matching_region: "Matching Region", load_port: "Load Port", discharge_port: "Discharge Port",
  del_port: "Delivery Port", redel_port: "Redelivery Port", port: "Port",
  open_date: "Open Date", close_date: "Close Date",
  laycan_start_date: "Laycan Start", laycan_end_date: "Laycan End",
  duration: "Duration", dwt: "DWT", pic: "Person in Charge",
  email_id: "Email", phone_number: "Phone", restriction: "Restrictions", reason: "Reason",
};

function PipelineBadge({ method }: { method: string }) {
  const map: Record<string, { cls: string; label: string }> = {
    "rule-based": { cls: "bg-green-500/10 text-green-400 border-green-500/20", label: "Rule-Based" },
    "template": { cls: "bg-primary/10 text-primary border-primary/20", label: "Template Parser" },
    "llm-fallback": { cls: "bg-accent/10 text-accent border-accent/20", label: "LLM Fallback" },
  };
  const cfg = map[method] ?? { cls: "bg-muted text-muted-foreground border-border", label: method };
  return <span className={`inline-flex items-center px-2 py-0.5 text-xs font-medium rounded border ${cfg.cls}`}>{cfg.label}</span>;
}

function TypeBadge({ type }: { type: string }) {
  const map: Record<string, string> = {
    VC: "bg-blue-500/10 text-blue-400 border-blue-500/20",
    TC: "bg-purple-500/10 text-purple-400 border-purple-500/20",
    Tonnage: "bg-cyan-500/10 text-cyan-400 border-cyan-500/20",
    Mixed: "bg-orange-500/10 text-orange-400 border-orange-500/20",
    Unknown: "bg-muted text-muted-foreground border-border",
  };
  return <span className={`inline-flex items-center px-2 py-0.5 text-xs font-medium rounded border ${map[type] ?? map.Unknown}`}>{type}</span>;
}

export default function ExtractionDetail({ params }: { params: { id: string } }) {
  const id = parseInt(params.id);
  const { data: job, isLoading, error } = useGetExtraction(id, {
    query: { enabled: !!id, queryKey: getGetExtractionQueryKey(id) },
  });

  if (isLoading) {
    return (
      <div className="p-6 space-y-4">
        <Skeleton className="h-6 w-48" />
        <Skeleton className="h-32" />
        <Skeleton className="h-64" />
      </div>
    );
  }

  if (error || !job) {
    return (
      <div className="p-6">
        <Link href="/history" className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground mb-4">
          <ArrowLeft className="h-3.5 w-3.5" />Back to History
        </Link>
        <div className="p-6 bg-card border border-border rounded text-center">
          <p className="text-muted-foreground">Extraction not found</p>
        </div>
      </div>
    );
  }

  const entries = job.extractedEntries as unknown as ExtractedEntry[];

  return (
    <div className="p-6 space-y-5 max-w-5xl" data-testid="page-extraction-detail">
      {/* Back nav */}
      <Link href="/history" className="inline-flex items-center gap-1.5 text-xs text-muted-foreground hover:text-foreground transition-colors" data-testid="link-back">
        <ArrowLeft className="h-3.5 w-3.5" />Back to History
      </Link>

      {/* Meta */}
      <div className="bg-card border border-border rounded p-4">
        <div className="flex flex-wrap items-center gap-3 mb-4">
          <TypeBadge type={job.emailType} />
          <PipelineBadge method={job.pipeline} />
          {job.subject && <span className="text-sm font-medium text-foreground">{job.subject}</span>}
        </div>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
          <div>
            <p className="text-xs text-muted-foreground mb-1">Date</p>
            <p className="text-sm font-mono text-foreground">
              {new Date(job.createdAt).toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" })}
            </p>
          </div>
          <div>
            <p className="text-xs text-muted-foreground mb-1 flex items-center gap-1"><Clock className="h-3 w-3" />Processing</p>
            <p className="text-sm font-mono text-foreground">{job.processingMs}ms</p>
          </div>
          <div>
            <p className="text-xs text-muted-foreground mb-1 flex items-center gap-1"><DollarSign className="h-3 w-3" />Cost</p>
            <p className="text-sm font-mono text-accent">${job.estimatedCostUsd.toFixed(4)}</p>
          </div>
          <div>
            <p className="text-xs text-muted-foreground mb-1">Confidence</p>
            <div className="flex items-center gap-2">
              <div className="w-16 h-1.5 bg-muted rounded-full overflow-hidden">
                <div className="h-full bg-primary rounded-full" style={{ width: `${job.confidence * 100}%` }} />
              </div>
              <p className="text-sm font-mono text-foreground">{(job.confidence * 100).toFixed(1)}%</p>
            </div>
          </div>
        </div>
        <div className={`mt-4 flex items-center gap-1.5 text-xs py-1.5 px-2 rounded w-fit ${
          job.llmUsed ? "bg-accent/10 text-accent" : "bg-green-500/10 text-green-400"
        }`}>
          {job.llmUsed
            ? <><AlertTriangle className="h-3 w-3" />LLM was used</>
            : <><CheckCircle className="h-3 w-3" />Extracted without LLM</>
          }
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-5">
        {/* Original email */}
        <div className="space-y-2">
          <p className="text-xs font-medium text-muted-foreground uppercase tracking-widest">Original Email</p>
          <div className="bg-card border border-border rounded p-4 max-h-96 overflow-y-auto">
            <pre className="text-xs font-mono text-foreground/80 whitespace-pre-wrap break-words leading-relaxed">{job.emailText}</pre>
          </div>
        </div>

        {/* Extracted entries */}
        <div className="space-y-2">
          <p className="text-xs font-medium text-muted-foreground uppercase tracking-widest">Extracted Entries ({entries.length})</p>
          <div className="space-y-3 max-h-96 overflow-y-auto pr-1">
            {entries.length === 0 ? (
              <div className="bg-card border border-border rounded p-4 text-center text-sm text-muted-foreground">
                No entries were extracted
              </div>
            ) : (
              entries.map((entry, i) => (
                <div key={i} className="bg-card border border-border rounded overflow-hidden" data-testid={`entry-${i}`}>
                  <div className="flex items-center gap-2 px-3 py-2 border-b border-border bg-muted/10">
                    <TypeBadge type={entry.entryType} />
                    <PipelineBadge method={entry.extractionMethod} />
                    <span className="text-xs text-muted-foreground ml-auto">{(entry.confidence * 100).toFixed(0)}% confidence</span>
                  </div>
                  <div className="p-3">
                    {Object.entries(entry.fields)
                      .filter(([, v]) => v !== null && v !== undefined && v !== "")
                      .map(([key, val]) => (
                        <div key={key} className="flex gap-2 py-1 border-b border-border/30 last:border-0 text-xs">
                          <span className="text-muted-foreground font-mono w-36 shrink-0">{FIELD_LABELS[key] ?? key}</span>
                          <span className="text-foreground">{String(val)}</span>
                        </div>
                      ))}
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState } from "react";
import { useListRegions, useListPorts, useListVesselSizes } from "@workspace/api-client-react";
import { Skeleton } from "@/components/ui/skeleton";
import { Search } from "lucide-react";

type Tab = "regions" | "ports" | "vessels";

function SearchInput({ value, onChange, placeholder }: { value: string; onChange: (v: string) => void; placeholder: string }) {
  return (
    <div className="relative">
      <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground" />
      <input
        type="search"
        value={value}
        onChange={e => onChange(e.target.value)}
        placeholder={placeholder}
        className="w-full pl-8 pr-3 py-2 text-sm bg-card border border-border rounded text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-1 focus:ring-primary"
        data-testid="input-knowledge-search"
      />
    </div>
  );
}

export default function Knowledge() {
  const [activeTab, setActiveTab] = useState<Tab>("regions");
  const [search, setSearch] = useState("");

  const { data: regions, isLoading: loadingRegions } = useListRegions();
  const { data: ports, isLoading: loadingPorts } = useListPorts();
  const { data: vessels, isLoading: loadingVessels } = useListVesselSizes();

  const tabs: { id: Tab; label: string; count?: number }[] = [
    { id: "regions", label: "Regions", count: regions?.length },
    { id: "ports", label: "Ports", count: ports?.length },
    { id: "vessels", label: "Vessel Sizes", count: vessels?.length },
  ];

  const q = search.toLowerCase();
  const filteredRegions = regions?.filter(r => !q || r.code.toLowerCase().includes(q) || r.fullName.toLowerCase().includes(q)) ?? [];
  const filteredPorts = ports?.filter(p => !q || p.code.toLowerCase().includes(q) || p.fullName.toLowerCase().includes(q)) ?? [];
  const filteredVessels = vessels?.filter(v => !q || v.name.toLowerCase().includes(q)) ?? [];

  const isLoading = loadingRegions || loadingPorts || loadingVessels;

  return (
    <div className="p-6 space-y-5" data-testid="page-knowledge">
      <div>
        <h1 className="text-xl font-bold text-foreground tracking-tight">Maritime Knowledge Base</h1>
        <p className="text-sm text-muted-foreground mt-0.5">Reference dictionaries used by the extraction engine</p>
      </div>

      {/* Tabs */}
      <div className="flex items-center gap-1 border-b border-border">
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => { setActiveTab(tab.id); setSearch(""); }}
            className={`px-4 py-2 text-sm font-medium border-b-2 -mb-px transition-colors ${
              activeTab === tab.id
                ? "border-primary text-primary"
                : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
            data-testid={`tab-${tab.id}`}
          >
            {tab.label}
            {tab.count !== undefined && (
              <span className="ml-1.5 text-xs text-muted-foreground font-mono">({tab.count})</span>
            )}
          </button>
        ))}
      </div>

      {/* Search */}
      <div className="max-w-sm">
        <SearchInput
          value={search}
          onChange={setSearch}
          placeholder={`Search ${activeTab}...`}
        />
      </div>

      {/* Content */}
      <div className="bg-card border border-border rounded overflow-hidden">
        {isLoading ? (
          <div className="p-4 space-y-2">
            {[...Array(6)].map((_, i) => <Skeleton key={i} className="h-9" />)}
          </div>
        ) : activeTab === "regions" ? (
          <table className="w-full text-xs">
            <thead>
              <tr className="border-b border-border bg-muted/20">
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest w-28">Code</th>
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest">Full Name</th>
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest">Category</th>
              </tr>
            </thead>
            <tbody>
              {filteredRegions.length === 0 ? (
                <tr><td colSpan={3} className="px-4 py-8 text-center text-muted-foreground">No results</td></tr>
              ) : filteredRegions.map(r => (
                <tr key={r.code} className="border-b border-border/40 hover:bg-white/2 transition-colors" data-testid={`row-region-${r.code}`}>
                  <td className="px-4 py-2.5 font-mono font-bold text-primary">{r.code}</td>
                  <td className="px-4 py-2.5 text-foreground">{r.fullName}</td>
                  <td className="px-4 py-2.5 text-muted-foreground">{r.category}</td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : activeTab === "ports" ? (
          <table className="w-full text-xs">
            <thead>
              <tr className="border-b border-border bg-muted/20">
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest w-32">Code</th>
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest">Full Name</th>
              </tr>
            </thead>
            <tbody>
              {filteredPorts.length === 0 ? (
                <tr><td colSpan={2} className="px-4 py-8 text-center text-muted-foreground">No results</td></tr>
              ) : filteredPorts.map(p => (
                <tr key={p.code} className="border-b border-border/40 hover:bg-white/2 transition-colors" data-testid={`row-port-${p.code}`}>
                  <td className="px-4 py-2.5 font-mono font-bold text-primary">{p.code}</td>
                  <td className="px-4 py-2.5 text-foreground">{p.fullName}</td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <table className="w-full text-xs">
            <thead>
              <tr className="border-b border-border bg-muted/20">
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest">Vessel Class</th>
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest">Min DWT</th>
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest">Max DWT</th>
                <th className="text-left px-4 py-2.5 text-muted-foreground font-medium uppercase tracking-widest">Notes</th>
              </tr>
            </thead>
            <tbody>
              {filteredVessels.length === 0 ? (
                <tr><td colSpan={4} className="px-4 py-8 text-center text-muted-foreground">No results</td></tr>
              ) : filteredVessels.map(v => (
                <tr key={v.name} className="border-b border-border/40 hover:bg-white/2 transition-colors" data-testid={`row-vessel-${v.name}`}>
                  <td className="px-4 py-2.5 font-bold text-foreground">{v.name}</td>
                  <td className="px-4 py-2.5 font-mono text-primary">{v.minDwt.toLocaleString()}</td>
                  <td className="px-4 py-2.5 font-mono text-primary">{v.maxDwt ? v.maxDwt.toLocaleString() : "—"}</td>
                  <td className="px-4 py-2.5 text-muted-foreground">{v.description ?? ""}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}

