   214→      const end = `${yr}-${m}-${d2.padStart(2, "0")}`;
   215→      return { start, end };
   216→    }
   217→  }
   218→
   219→  // Pattern: "END JULY, 2025"
   220→  const endMonthMatch = upper.match(/(?:END|LATE)\s+([A-Z]+)[,.\s]+(\d{4})/);
   221→  if (endMonthMatch) {
   222→    const [, mon, yr] = endMonthMatch;
   223→    const m = MONTH_MAP[mon];
   224→    if (m) {
   225→      const lastDay = new Date(parseInt(yr), parseInt(m), 0).getDate();
   226→      const start = `${yr}-${m}-${(lastDay - 5).toString().padStart(2, "0")}`;
   227→      const end = `${yr}-${m}-${lastDay.toString().padStart(2, "0")}`;
   228→      return { start, end };
   229→    }
   230→  }
   231→
   232→  // Pattern: "EARLY JULY" or "MID AUGUST"
   233→  const midEarlyMatch = upper.match(/(?:EARLY|MID|BEGINNING OF)\s+([A-Z]+)[,.\s]+(\d{4})/);
   234→  if (midEarlyMatch) {
   235→    const [, mon, yr] = midEarlyMatch;
   236→    const m = MONTH_MAP[mon];
   237→    if (m) {
   238→      const prefix = upper.includes("EARLY") ? "01" : "15";
   239→      const end = upper.includes("EARLY") ? "10" : "20";
   240→      return { start: `${yr}-${m}-${prefix}`, end: `${yr}-${m}-${end}` };
   241→    }
   242→  }
   243→
   244→  // Pattern: "1-10 Aug" or "15-18 July"
   245→  const simpleRange = upper.match(/(\d{1,2})\s*[-–]\s*(\d{1,2})\s+([A-Z]+)/);
   246→  if (simpleRange) {
   247→    const [, d1, d2, mon] = simpleRange;
   248→    const m = MONTH_MAP[mon];
