   258→  // Pattern: "22ND JULY" single date
   259→  const singleDate = upper.match(/(\d{1,2})(?:ST|ND|RD|TH)?\s+([A-Z]+)[,.\s]+(\d{4})/);
   260→  if (singleDate) {
   261→    const [, d, mon, yr] = singleDate;
   262→    const m = MONTH_MAP[mon];
   263→    if (m) {
   264→      const start = `${yr}-${m}-${d.padStart(2, "0")}`;
   265→      const endDay = new Date(parseInt(yr), parseInt(m) - 1, parseInt(d) + 5).getDate();
   266→      const end = `${yr}-${m}-${endDay.toString().padStart(2, "0")}`;
   267→      return { start, end };
   268→    }
   269→  }
   270→
   271→  // Pattern: "PROMPT" or "SPOT"
   272→  if (upper.includes("PROMPT") || upper.includes("SPOT")) {
   273→    const today = new Date();
   274→    const fmt = (d: Date) => d.toISOString().split("T")[0];
   275→    const end = new Date(today); end.setDate(end.getDate() + 5);
   276→    return { start: fmt(today), end: fmt(end) };
   277→  }
   278→
   279→  return { start: null, end: null };
