   295→        if (VESSEL_SIZE_MAP[clean]) {
   296→          min = Math.min(min, VESSEL_SIZE_MAP[clean].min);
   297→          max = Math.max(max, VESSEL_SIZE_MAP[clean].max);
   298→          found = true;
   299→        }
