   308→  if (rangeMatch) {
   309→    const factor = rangeMatch[0].includes("K") ? 1000 : 1;
   310→    return {
   311→      min: parseFloat(rangeMatch[1].replace(",", "")) * factor,
   312→      max: parseFloat(rangeMatch[2].replace(",", "")) * factor,
   313→    };
   314→  }
   315→
   316→  // Single DWT
   317→  const singleMatch = upper.match(/(\d+(?:[.,]\d+)?)\s*K?\s*DWT/);
   318→  if (singleMatch) {
   319→    const factor = singleMatch[0].includes("K") ? 1000 : 1;
   320→    const val = parseFloat(singleMatch[1].replace(",", "")) * factor;
